diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index c06d5c759634..28bc9a679508 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1056,6 +1056,114 @@ static Value *foldPowerOf2AndShiftedMask(ICmpInst *Cmp0, ICmpInst *Cmp1,
   }
   return nullptr;
 }
+/// Fold (X != C) & ((X + (-C)) ule Y) into (X + (-C-1)) ult Y.
+/// Fold (X != C) & (Y uge (X + (-C))) into Y ugt (X + (-C-1)).
+/// Fold (X == C) | ((X + (-C)) ugt Y) into (X + (-C-1)) uge Y.
+/// Fold (X == C) | (Y ult (X + (-C))) into Y ule (X + (-C-1)).
+/// 
+/// For AND: When X != C, X + (-C) doesn't wrap to 0, so (X + (-C)) ule Y is
+/// equivalent to (X + (-C - 1)) ult Y.
+/// For OR: When X == C, the condition is satisfied. Otherwise, when X != C,
+/// (X + (-C)) ugt Y is equivalent to (X + (-C - 1)) uge Y.
+static Value *foldAndOrOfICmpEqConstantAndICmp(ICmpInst *EqICmp, ICmpInst *OtherICmp,
+                                                bool IsAnd,
+                                                InstCombiner::BuilderTy &Builder) {
+  // Match the equality/inequality comparison: icmp eq/ne X, C
+  Value *X;
+  ICmpInst::Predicate EqPred;
+  const APInt *C;
+  if (!match(EqICmp, m_ICmp(EqPred, m_Value(X), m_APInt(C))))
+    return nullptr;
+  
+  // For AND, we need icmp ne; for OR, we need icmp eq
+  if (IsAnd && EqPred != ICmpInst::ICMP_NE)
+    return nullptr;
+  if (!IsAnd && EqPred != ICmpInst::ICMP_EQ)
+    return nullptr;
+  
+  // Match the other comparison
+  Value *Op0 = OtherICmp->getOperand(0);
+  Value *Op1 = OtherICmp->getOperand(1);
+  ICmpInst::Predicate OtherPred = OtherICmp->getPredicate();
+  
+  // Check for (X + (-C)) ule Y or Y uge (X + (-C)) for AND
+  // Check for (X + (-C)) ugt Y or Y ult (X + (-C)) for OR
+  Value *Y;
+  Value *AddOp = nullptr;
+  bool Commuted = false;
+  
+  if (IsAnd) {
+    if (OtherPred == ICmpInst::ICMP_ULE) {
+      // Standard: (X + (-C)) ule Y
+      const APInt *AddC;
+      if (match(Op0, m_c_Add(m_Specific(X), m_APInt(AddC)))) {
+        if (*AddC == -(*C)) {
+          AddOp = Op0;
+          Y = Op1;
+        }
+      }
+    } else if (OtherPred == ICmpInst::ICMP_UGE) {
+      // Commuted: Y uge (X + (-C))
+      const APInt *AddC;
+      if (match(Op1, m_c_Add(m_Specific(X), m_APInt(AddC)))) {
+        if (*AddC == -(*C)) {
+          AddOp = Op1;
+          Y = Op0;
+          Commuted = true;
+        }
+      }
+    }
+  } else { // OR case
+    if (OtherPred == ICmpInst::ICMP_UGT) {
+      // Standard: (X + (-C)) ugt Y
+      const APInt *AddC;
+      if (match(Op0, m_c_Add(m_Specific(X), m_APInt(AddC)))) {
+        if (*AddC == -(*C)) {
+          AddOp = Op0;
+          Y = Op1;
+        }
+      }
+    } else if (OtherPred == ICmpInst::ICMP_ULT) {
+      // Commuted: Y ult (X + (-C))
+      const APInt *AddC;
+      if (match(Op1, m_c_Add(m_Specific(X), m_APInt(AddC)))) {
+        if (*AddC == -(*C)) {
+          AddOp = Op1;
+          Y = Op0;
+          Commuted = true;
+        }
+      }
+    }
+  }
+  
+  if (!AddOp)
+    return nullptr;
+  
+  // Compute the new constant: -C - 1
+  APInt NewC = -(*C) - 1;
+  
+  // Build (X + (-C - 1))
+  Type *Ty = X->getType();
+  Value *NewAdd = Builder.CreateAdd(X, ConstantInt::get(Ty, NewC));
+  
+  // For AND standard: return (X + (-C-1)) ult Y
+  // For AND commuted: return Y ugt (X + (-C-1))
+  // For OR standard: return (X + (-C-1)) uge Y
+  // For OR commuted: return Y ule (X + (-C-1))
+  if (IsAnd) {
+    if (Commuted)
+      return Builder.CreateICmp(ICmpInst::ICMP_UGT, Y, NewAdd);
+    else
+      return Builder.CreateICmp(ICmpInst::ICMP_ULT, NewAdd, Y);
+  } else {
+    if (Commuted)
+      return Builder.CreateICmp(ICmpInst::ICMP_ULE, Y, NewAdd);
+    else
+      return Builder.CreateICmp(ICmpInst::ICMP_UGE, NewAdd, Y);
+  }
+}
+
+

 /// Commuted variants are assumed to be handled by calling this function again
 /// with the parameters swapped.
@@ -3099,6 +3207,14 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
   if (Value *V = foldPowerOf2AndShiftedMask(LHS, RHS, IsAnd, Builder))
     return V;

+  // Fold (X != C) & ((X + (-C)) ule Y) into (X + (-C-1)) ult Y
+  // Fold (X == C) | ((X + (-C)) ugt Y) into (X + (-C-1)) uge Y
+  if (Value *V = foldAndOrOfICmpEqConstantAndICmp(LHS, RHS, IsAnd, Builder))
+    return V;
+  if (Value *V = foldAndOrOfICmpEqConstantAndICmp(RHS, LHS, IsAnd, Builder))
+    return V;
+
